/**
 * Section — titled content region for React PDF documents.
 *
 * @registryTitle PDF Section
 * @registryDescription Titled document section with optional description and wrapping controls.
 * @registryCategory layout
 * @registryDemos basic=Basic, no-wrap=No Wrap
 */

import * as React from "react";
import { View, Text, StyleSheet } from "@react-pdf/renderer";
import type { Style } from "@react-pdf/types";
import {
  mergePdfStyles,
  type PdfStyleInput,
  usePdfTheme,
} from "@/lib/pdf-theme";

export interface PdfSectionProps {
  title?: string;
  description?: string;
  children: React.ReactNode;
  noWrap?: boolean;
  style?: PdfStyleInput;
}

export function PdfSection({
  title,
  description,
  children,
  noWrap = false,
  style,
}: PdfSectionProps) {
  const theme = usePdfTheme();
  const styles = StyleSheet.create({
    section: {
      marginBottom: theme.spacing.section,
      paddingTop: title ? theme.spacing.sm : 0,
    } as Style,
    title: {
      color: theme.colors.foreground,
      fontFamily: theme.typography.fontFamily,
      fontSize: theme.typography.lg,
      fontWeight: 700,
      marginBottom: 4,
    } as Style,
    description: {
      color: theme.colors.mutedForeground,
      fontFamily: theme.typography.fontFamily,
      fontSize: theme.typography.sm,
      lineHeight: 1.45,
      marginBottom: theme.spacing.sm,
    } as Style,
  });

  return (
    <View wrap={!noWrap} style={mergePdfStyles(styles.section, style)}>
      {title ? <Text style={styles.title}>{title}</Text> : null}
      {description ? (
        <Text style={styles.description}>{description}</Text>
      ) : null}
      {children}
    </View>
  );
}

/**
 * PDF Theme — shared theme tokens and helpers for edbn/ui PDF components.
 *
 * @registryTitle PDF Theme
 * @registryDescription Theme provider, default tokens, and style helpers for PDF components.
 * @registryVariant pdf
 * @registryType registry:lib
 */

import * as React from "react";
import type { Style } from "@react-pdf/types";

// ---- TYPES -----------------------------------------------------------------

export interface PdfTheme {
  colors: {
    background: string;
    foreground: string;
    mutedForeground: string;
    border: string;
    primary: string;
    primaryForeground: string;
    muted: string;
    destructive: string;
    warning: string;
    success: string;
  };
  spacing: {
    page: number;
    section: number;
    gap: number;
    sm: number;
    md: number;
    lg: number;
  };
  radii: {
    sm: number;
    md: number;
    lg: number;
  };
  typography: {
    fontFamily: string;
    monoFontFamily: string;
    xs: number;
    sm: number;
    base: number;
    lg: number;
    xl: number;
    xxl: number;
  };
}

export type PdfStyleInput = Style | Style[] | null | undefined | false;

// ---- DEFAULT THEME ---------------------------------------------------------

export const defaultPdfTheme: PdfTheme = {
  colors: {
    background: "#ffffff",
    foreground: "#111827",
    mutedForeground: "#6b7280",
    border: "#d1d5db",
    primary: "#2563eb",
    primaryForeground: "#ffffff",
    muted: "#f3f4f6",
    destructive: "#dc2626",
    warning: "#b45309",
    success: "#15803d",
  },
  spacing: {
    page: 36,
    section: 16,
    gap: 10,
    sm: 6,
    md: 10,
    lg: 16,
  },
  radii: {
    sm: 4,
    md: 7,
    lg: 10,
  },
  typography: {
    fontFamily: "Helvetica",
    monoFontFamily: "Courier",
    xs: 8,
    sm: 9,
    base: 10.5,
    lg: 13,
    xl: 18,
    xxl: 28,
  },
};

// ---- CONTEXT ---------------------------------------------------------------

const PdfThemeContext = React.createContext<PdfTheme>(defaultPdfTheme);

export interface PdfThemeProviderProps {
  theme?: Partial<PdfTheme>;
  children: React.ReactNode;
}

function mergeTheme(theme?: Partial<PdfTheme>): PdfTheme {
  if (!theme) return defaultPdfTheme;
  return {
    colors: { ...defaultPdfTheme.colors, ...theme.colors },
    spacing: { ...defaultPdfTheme.spacing, ...theme.spacing },
    radii: { ...defaultPdfTheme.radii, ...theme.radii },
    typography: { ...defaultPdfTheme.typography, ...theme.typography },
  };
}

export function PdfThemeProvider({ theme, children }: PdfThemeProviderProps) {
  const resolvedTheme = React.useMemo(() => mergeTheme(theme), [theme]);
  return (
    <PdfThemeContext.Provider value={resolvedTheme}>
      {children}
    </PdfThemeContext.Provider>
  );
}

export function usePdfTheme(): PdfTheme {
  return React.useContext(PdfThemeContext) ?? defaultPdfTheme;
}

// ---- STYLE HELPERS ---------------------------------------------------------

export function mergePdfStyles(...styles: PdfStyleInput[]): Style[] {
  return styles.flatMap((style) => {
    if (!style) return [];
    return Array.isArray(style) ? style.filter(Boolean) : [style];
  });
}

export function getToneColor(theme: PdfTheme, tone?: string): string {
  switch (tone) {
    case "primary":
      return theme.colors.primary;
    case "muted":
      return theme.colors.mutedForeground;
    case "destructive":
      return theme.colors.destructive;
    case "warning":
      return theme.colors.warning;
    case "success":
      return theme.colors.success;
    default:
      return theme.colors.foreground;
  }
}
